import React from 'react';

const ParentDashboard = () => {
  return (
    <div>
      <h3 className="fw-bold mb-4">Dashboard</h3>
      <div className="p-5 text-center text-muted border rounded bg-light" style={{ borderStyle: 'dashed' }}>
        <p className="mb-0">Dashboard content coming soon...</p>
      </div>
    </div>
  );
};

export default ParentDashboard;
